class Solution {
public:
    int magicalString(int n) {
        vector<int> s(n + 1, 0);
        s[0] = 1;
        s[1] = 2;
        s[2] = 2;
        int head = 2, tail = 3, num = 1;
        while (tail < n) {
            for (int i = 0; i < s[head]; i++) {
                if (tail >= n) break;
                s[tail] = num ^ 3;
                tail++;
            }
            head++;
            num ^= 3;
        }
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == 1) count++;
        }
        return count;
    }
};
